sql:
SELECT move_id, evaluation
FROM move_analysis
WHERE engine_name = 'Stockfish' AND analysis_depth > 20;

SELECT AVG(turns) AS average_turns
FROM games
WHERE white_rating > (SELECT AVG(black_rating) FROM games);

external_knowledge:
Decent range of ratings: 1800 to 2000;
Last decade: between 2010 and 2022;
Slav Defense: a popular chess opening;
Rated games: official games that impact player rankings;
Victory status: the outcome of the game, e.g., win, loss, draw.

sql:
SELECT player_id
FROM player_stats
WHERE average_rating = (SELECT MAX(average_rating) FROM player_stats);

SELECT DISTINCT p.player_id, p.username
FROM players p
JOIN (
    SELECT white_id AS player_id FROM games
    UNION
    SELECT black_id AS player_id FROM games
) AS participants ON p.player_id = participants.player_id
WHERE p.player_id IN (
    SELECT player_id FROM game_comments
);

SELECT games.game_id, openings.name
FROM games
JOIN openings ON games.opening_id = openings.opening_id;

SELECT username, rating
FROM players
WHERE rating < (SELECT AVG(rating) FROM players);

SELECT engine_name, AVG(evaluation) AS AverageEvaluation
FROM move_analysis
GROUP BY engine_name;
